interface Todo {
  id: number;
  text: string;
  done: boolean;
}

todos: Todo[] = [];
filter: 'all' | 'active' | 'completed' = 'all';
private seq = 0;

add(text: string) {
  this.todos = [
    ...this.todos,
    { id: ++this.seq, text, done: false }
  ];
}

toggle(id: number) {
  this.todos = this.todos.map(todo =>
    todo.id === id
      ? { ...todo, done: !todo.done }
      : todo
  );
}

remove(id: number) {
  this.todos = this.todos.filter(todo => todo.id !== id);
}

trackById(index: number, todo: Todo) {
  return todo.id;
}

get visibleTodos() {
  switch (this.filter) {
    case 'active':
      return this.todos.filter(t => !t.done);
    case 'completed':
      return this.todos.filter(t => t.done);
    default:
      return this.todos;
  }
}

@Input() columns!: Column[];
@Input() rows: any[] = [];

sortKey = '';
dir: 'asc' | 'desc' = 'asc';

sort(column: string) {
  this.dir =
    this.sortKey === column && this.dir === 'asc'
      ? 'desc'
      : 'asc';

  this.sortKey = column;

  this.rows = [...this.rows].sort((a, b) => {
    const result = a[column] > b[column] ? 1 : -1;
    return this.dir === 'asc' ? result : -result;
  });
}

