@Injectable({ providedIn: 'root' })
export class UserService {

  private users$?: Observable<User[]>;

  getUsers() {
    if (!this.users$) {
      this.users$ = this.http
        .get<User[]>('/api/users')
        .pipe(shareReplay(1));
    }

    return this.users$;
  }
}

